// A API de fases retorna um array direto, não { results: [...] }
const fases = $input.all().map(item => item.json);

console.log(`Total de fases encontradas: ${fases.length}`);

// Cria o mapa { id: nome }
const mapaFases = {};
fases.forEach(fase => {
  mapaFases[fase.id] = fase.nome;
});

console.log('Mapa de fases criado:', mapaFases);

return [{
  json: {
    fases_map: mapaFases
  }
}];

// Pega resposta da API de cards
const response = $input.first().json;
const cards = response.results || [];

// Pega accessToken do nó fazLogin
const accessToken = $('fazLogin').item.json.accessToken;

// Pega baseUrl do nó configInicial
const baseUrl = $('configInicial').item.json.baseUrl;

// Pega mapa de fases do nó criarMapaFases
const mapaFases = $('criarMapaFases').item.json.fases_map;

console.log(`Total de cards encontrados: ${cards.length}`);

// Função para limpar HTML
function limparHTML(html) {
  if (!html) return '';

  let limpo = html;

  // Remove imagens base64
  limpo = limpo.replace(/data:image\/[^;]+;base64,[A-Za-z0-9+/=]+/gi, '[imagem]');

  // Remove tags de imagem
  limpo = limpo.replace(/<img[^>]*>/gi, '[imagem]');

  // Remove anexos
  limpo = limpo.replace(/<span[^>]*attachment-block[^>]*>.*?<\/span>/gi, '[anexo]');

  // Remove tags HTML mas mantém o texto
  limpo = limpo.replace(/<[^>]+>/g, ' ');

  // Remove espaços múltiplos
  limpo = limpo.replace(/\s+/g, ' ').trim();

  return limpo;
}

// Converte tempo_decorrido "HH:MM:SS" para horas decimais
function parseTempoDecorrido(tempoStr) {
  if (!tempoStr || tempoStr === "00:00:00") return 0;

  const partes = tempoStr.split(':');
  if (partes.length < 2) return 0;

  const horas = parseInt(partes[0]) || 0;
  const minutos = parseInt(partes[1]) || 0;
  const segundos = parseInt(partes[2]) || 0;

  return horas + (minutos / 60) + (segundos / 3600);
}

// Processa cada card COM TODOS OS DADOS
const cardsLimpos = cards.map(card => {
  const tempoTrabalhadoHoras = parseTempoDecorrido(card.tempo_decorrido);

  return {
    // IDs
    id: card.id,
    chamado: card.id,

    // Informações do card
    titulo: card.titulo || `Card #${card.id}`,
    descricao_limpa: limparHTML(card.descricao),

    // Fase
    fase_atual: card.fase,
    fase_atual_nome: mapaFases[card.fase] || 'Desconhecida',

    // Responsáveis
    responsaveis: (card.responsaveis || []).map(r => r.nome),

    // Métricas
    tempo_decorrido: card.tempo_decorrido,
    tempo_trabalhado_horas: tempoTrabalhadoHoras,
    pontos_totais: card.pontos_totais || 0,
    em_andamento: card.em_andamento,

    // Datas
    data_criacao: card.data_criacao,
    data_atualizacao: card.data_atualizacao || null,
    data_conclusao: card.data_conclusao,
    data_prevista: card.data_prevista,

    // Tags
    tags: card.tags || [],

    // Projeto
    projeto_info: card.projeto_info,

    // Auth
    _auth: {
      accessToken: accessToken,
      baseUrl: baseUrl
    }
  };
});

console.log(`Cards limpos: ${cardsLimpos.length}`);

if (cardsLimpos.length > 0) {
  const exemplo = cardsLimpos.find(c => c.tempo_trabalhado_horas > 0) || cardsLimpos[0];
  console.log(`Exemplo - Card #${exemplo.id}: tempo_decorrido="${exemplo.tempo_decorrido}" → ${exemplo.tempo_trabalhado_horas.toFixed(2)}h`);
}

return cardsLimpos.map(card => ({ json: card }));

// Pega todos os logs retornados da API
const todosLogs = $input.all().map(item => item.json);
const totalLogs = todosLogs.length;
console.log('Total de logs recebidos: ' + totalLogs);

// Pega o card COMPLETO do Loop Over Items
const cardCompleto = $('Loop Over Items').item.json;
const cardId = cardCompleto.id;

console.log('Processando logs do card #' + cardId);

// Define período de análise (últimos 200 dias)
const duzentosDiasAtras = new Date();
duzentosDiasAtras.setDate(duzentosDiasAtras.getDate() - 200);

// Filtra apenas mudanças de fase nos últimos 200 dias
const logsFiltrados = todosLogs
  .filter(log => {
    if (log.campo_back !== 'fase') return false;
    const dataLog = new Date(log.data);
    if (dataLog < duzentosDiasAtras) return false;
    return true;
  })
  .map(log => ({
    data: log.data,
    de: log.valor_anterior || 'Criação',
    para: log.valor_posterior,
    usuario: log.usuario || 'Sistema',
    frase: log.frase
  }))
  .sort((a, b) => new Date(a.data) - new Date(b.data));

const totalLogsFiltrados = logsFiltrados.length;
console.log('Card #' + cardId + ': ' + totalLogsFiltrados + ' logs de fase relevantes');

// Calcula tempo em cada fase (tempo decorrido, não trabalhado)
function calcularTempoPorFase(logs) {
  const temposPorFase = {};

  for (let i = 0; i < logs.length - 1; i++) {
    const logAtual = logs[i];
    const logProximo = logs[i + 1];

    const inicio = new Date(logAtual.data);
    const fim = new Date(logProximo.data);
    const horas = (fim - inicio) / (1000 * 60 * 60);

    if (!temposPorFase[logAtual.para]) {
      temposPorFase[logAtual.para] = 0;
    }
    temposPorFase[logAtual.para] += horas;
  }

  if (logs.length > 0) {
    const ultimoLog = logs[logs.length - 1];
    const inicio = new Date(ultimoLog.data);
    const agora = new Date();
    const horas = (agora - inicio) / (1000 * 60 * 60);

    const faseAtualDoLog = ultimoLog.para;
    if (!temposPorFase[faseAtualDoLog]) {
      temposPorFase[faseAtualDoLog] = 0;
    }
    temposPorFase[faseAtualDoLog] += horas;
  }

  return temposPorFase;
}

const tempoPorFase = calcularTempoPorFase(logsFiltrados);

// Identifica qual fase teve maior tempo
let maiorTempoFase = null;
let maiorTempo = 0;
for (const [fase, horas] of Object.entries(tempoPorFase)) {
  if (horas > maiorTempo) {
    maiorTempo = horas;
    maiorTempoFase = fase;
  }
}

// Calcula dias na fase atual
let diasNaFaseAtual = null;
if (logsFiltrados.length > 0) {
  const ultimoLog = logsFiltrados[logsFiltrados.length - 1];
  const dataUltimaMovimentacao = new Date(ultimoLog.data);
  const agora = new Date();
  const diffMs = agora - dataUltimaMovimentacao;
  diasNaFaseAtual = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  console.log('Card #' + cardId + ': última movimentação em ' + ultimoLog.data + ', há ' + diasNaFaseAtual + ' dias na fase ' + ultimoLog.para);
}

console.log('Card #' + cardId + ' está atualmente em: ' + cardCompleto.fase_atual_nome);
console.log('Card #' + cardId + ' tempo trabalhado: ' + (cardCompleto.tempo_trabalhado_horas || 0).toFixed(2) + 'h');

// RETORNA O CARD COMPLETO com os dados de trajetória
return [{
  json: {
    // Dados originais do card
    id: cardCompleto.id,
    chamado: cardCompleto.chamado,
    titulo: cardCompleto.titulo,
    descricao_limpa: cardCompleto.descricao_limpa,
    fase_atual: cardCompleto.fase_atual,
    fase_atual_nome: cardCompleto.fase_atual_nome,
    responsaveis: cardCompleto.responsaveis,
    tempo_decorrido: cardCompleto.tempo_decorrido,
    tempo_trabalhado_horas: cardCompleto.tempo_trabalhado_horas,
    pontos_totais: cardCompleto.pontos_totais,
    em_andamento: cardCompleto.em_andamento,
    data_criacao: cardCompleto.data_criacao,
    data_atualizacao: cardCompleto.data_atualizacao,
    data_conclusao: cardCompleto.data_conclusao,
    data_prevista: cardCompleto.data_prevista,
    tags: cardCompleto.tags,
    projeto_info: cardCompleto.projeto_info,

    // Dados calculados dos logs
    logs_fase: logsFiltrados,
    tempo_por_fase: tempoPorFase,
    dias_na_fase_atual: diasNaFaseAtual,
    maior_tempo_fase: maiorTempoFase ? {
      fase: maiorTempoFase,
      horas: Math.round(maiorTempo)
    } : null,

    dados_usuario: todosLogs.length > 0 ? todosLogs[0].dados_usuario : null
  }
}];

// Recebe output do juntarTodosCards
const input = $input.first().json;
const todosCards = input.data || [];
const fasesMap = input.fases_map || {};

console.log('=== PREPARANDO DADOS PARA WF2 ===');
console.log(`Total de cards: ${todosCards.length}`);

// ✅ DINÂMICO: Pega info do projeto do primeiro card (todos têm a mesma)
const projetoInfo = todosCards.length > 0 && todosCards[0].projeto_info 
  ? todosCards[0].projeto_info 
  : {
      id: $('configInicial').item.json.projeto_id,
      nome: "Projeto Sem Nome"
    };

console.log(`Projeto: ${projetoInfo.nome} (ID: ${projetoInfo.id})`);

// Calcula resumo
const resumo = {
  total_cards: todosCards.length,
  por_status: {
    concluidos: todosCards.filter(c => 
      c.fase_atual_nome && c.fase_atual_nome.toLowerCase().includes('conclu')
    ).length,
    em_andamento: todosCards.filter(c => 
      c.fase_atual_nome && c.fase_atual_nome.toLowerCase().includes('andamento')
    ).length,
    pendentes: todosCards.filter(c => {
      if (!c.fase_atual_nome) return false;
      const fase = c.fase_atual_nome.toLowerCase();
      return fase.includes('sprint') || fase.includes('backlog') || fase.includes('fila');
    }).length,
    outros: todosCards.filter(c => {
      if (!c.fase_atual_nome) return false;
      const fase = c.fase_atual_nome.toLowerCase();
      return !fase.includes('conclu') && 
             !fase.includes('andamento') && 
             !fase.includes('sprint') && 
             !fase.includes('backlog') && 
             !fase.includes('fila');
    }).length
  },
  por_fase: {},
  alertas: {
    cards_travados: todosCards.filter(c => 
      c.dias_na_fase_atual && c.dias_na_fase_atual >= 30
    ).length,
    cards_travados_ids: todosCards
      .filter(c => c.dias_na_fase_atual && c.dias_na_fase_atual >= 30)
      .map(c => c.id)
  }
};

// Conta cards por fase
todosCards.forEach(card => {
  const fase = card.fase_atual_nome || 'Sem Fase';
  if (!resumo.por_fase[fase]) {
    resumo.por_fase[fase] = 0;
  }
  resumo.por_fase[fase]++;
});

console.log('📊 Resumo gerado:');
console.log(`   Total: ${resumo.total_cards}`);
console.log(`   Concluídos: ${resumo.por_status.concluidos}`);
console.log(`   Em Andamento: ${resumo.por_status.em_andamento}`);
console.log(`   Pendentes: ${resumo.por_status.pendentes}`);
console.log(`   Outros: ${resumo.por_status.outros}`);
console.log(`   Travados: ${resumo.alertas.cards_travados}`);

// Formato que o WF2 espera
return [{
  json: {
    projeto_info: projetoInfo,  // ✅ DINÂMICO agora!
    cards: todosCards,
    fases: fasesMap,
    resumo: resumo
  }
}];

// ============================================
// NÓ: identificarSprints
// Posição: entre juntarTodosCards e juntarComMapaFases
// ============================================

const input = $input.first().json;
const todosCards = input.cards || [];  // ✅ CORRIGIDO: era "data"

console.log('=== IDENTIFICANDO SPRINTS ===');
console.log(`Total de cards para analisar: ${todosCards.length}`);

// Colunas que indicam que o card foi "puxado para trabalho"
const COLUNAS_TRABALHO = ['Sprint Atual', 'Em Andamento'];

// Janela em dias para considerar "mesma sprint"
const JANELA_SPRINT_DIAS = 7;

// ============================================
// FUNÇÕES AUXILIARES (movidas para cima)
// ============================================
function getWeekNumber(date) {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
}

function formatDate(date) {
  return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')}`;
}

// ============================================
// PASSO 1: Extrair data de entrada em trabalho de cada card
// ============================================
const cardsComDataEntrada = todosCards.map(card => {
  let dataEntradaTrabalho = null;
  let colunaEntrada = null;

  // Procura o primeiro log onde entrou em coluna de trabalho
  if (card.logs_fase && card.logs_fase.length > 0) {
    for (const log of card.logs_fase) {
      if (COLUNAS_TRABALHO.includes(log.para)) {
        dataEntradaTrabalho = new Date(log.data);
        colunaEntrada = log.para;
        break; // Pega só a PRIMEIRA entrada
      }
    }
  }

  return {
    ...card,
    _analise: {
      data_entrada_trabalho: dataEntradaTrabalho,
      coluna_entrada: colunaEntrada
    }
  };
});

// ============================================
// PASSO 2: Agrupar cards por "onda" de entrada (sprint)
// ============================================

// Filtra cards que têm data de entrada e ordena por data
const cardsComData = cardsComDataEntrada
  .filter(c => c._analise.data_entrada_trabalho !== null)
  .sort((a, b) => a._analise.data_entrada_trabalho - b._analise.data_entrada_trabalho);

const cardsSemData = cardsComDataEntrada
  .filter(c => c._analise.data_entrada_trabalho === null);

console.log(`Cards com data de entrada: ${cardsComData.length}`);
console.log(`Cards sem data (backlog/standby): ${cardsSemData.length}`);

// Agrupa em sprints baseado na janela temporal
const sprints = [];
let sprintAtual = null;

for (const card of cardsComData) {
  const dataEntrada = card._analise.data_entrada_trabalho;

  if (sprintAtual === null) {
    // Primeira sprint
    sprintAtual = {
      inicio: dataEntrada,
      fim: dataEntrada,
      cards: [card.id]
    };
  } else {
    // Verifica se está dentro da janela da sprint atual
    const diffDias = (dataEntrada - sprintAtual.fim) / (1000 * 60 * 60 * 24);

    if (diffDias <= JANELA_SPRINT_DIAS) {
      // Ainda é a mesma sprint
      sprintAtual.fim = dataEntrada;
      sprintAtual.cards.push(card.id);
    } else {
      // Nova sprint
      sprints.push(sprintAtual);
      sprintAtual = {
        inicio: dataEntrada,
        fim: dataEntrada,
        cards: [card.id]
      };
    }
  }
}

// Adiciona a última sprint
if (sprintAtual !== null) {
  sprints.push(sprintAtual);
}

console.log(`Sprints identificadas: ${sprints.length}`);

// ============================================
// PASSO 3: Nomear sprints e criar mapa de lookup
// ============================================
const mapaCardSprint = {};
const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 
               'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

sprints.forEach((sprint, index) => {
  // Gera nome da sprint baseado na data de início
  const dataInicio = sprint.inicio;
  const ano = dataInicio.getFullYear();
  const semanaAno = getWeekNumber(dataInicio);

  // Nome legível: "Sprint Out/25"
  const nomeMes = meses[dataInicio.getMonth()];
  const anoAbrev = String(ano).slice(-2);

  sprint.nome = `Sprint ${nomeMes}/${anoAbrev} (#${index + 1})`;
  sprint.codigo = `${ano}-W${String(semanaAno).padStart(2, '0')}`;

  // Mapeia cada card para sua sprint
  sprint.cards.forEach(cardId => {
    mapaCardSprint[cardId] = {
      nome: sprint.nome,
      codigo: sprint.codigo,
      periodo: {
        inicio: sprint.inicio.toISOString(),
        fim: sprint.fim.toISOString()
      },
      total_cards_sprint: sprint.cards.length
    };
  });

  console.log(`${sprint.nome}: ${sprint.cards.length} cards (${formatDate(sprint.inicio)} a ${formatDate(sprint.fim)})`);
});

// ============================================
// PASSO 4: Enriquecer cards com info da sprint
// ============================================
const cardsEnriquecidos = todosCards.map(card => {
  const infoSprint = mapaCardSprint[card.id] || null;

  return {
    ...card,
    sprint_identificada: infoSprint ? infoSprint.nome : null,
    sprint_codigo: infoSprint ? infoSprint.codigo : null,
    sprint_info: infoSprint
  };
});

// ============================================
// OUTPUT - Mantém estrutura original + sprints
// ============================================
console.log('=== SPRINTS IDENTIFICADAS ===');
sprints.forEach(s => {
  console.log(`${s.nome}: cards [${s.cards.join(', ')}]`);
});

return [{
  json: {
    projeto_info: input.projeto_info,  // ✅ Preserva
    cards: cardsEnriquecidos,           // ✅ Cards com sprint
    fases: input.fases,                 // ✅ Preserva
    resumo: input.resumo,               // ✅ Preserva
    sprints_identificadas: sprints.map(s => ({
      nome: s.nome,
      codigo: s.codigo,
      periodo: {
        inicio: s.inicio.toISOString(),
        fim: s.fim.toISOString()
      },
      cards: s.cards,
      total: s.cards.length
    }))
  }
}];
